{
	Complex C1;
	Complex C2(5,6);
	Complex C3;

	cout<<"Input a complex number"<<endl;
	cin>>C3;

	cout<<C1<<C2<<C3;

	if(C1==C2)
		cout<<"C1 == C2"<<endl;
